<?php
 namespace WPAICG\AutoGPT\Cron\EventProcessor\Trigger; if (!defined('ABSPATH')) { exit; } function trigger_comment_reply_task_logic(int $task_id, array $task_config, ?string $last_run_time = null): void { global $wpdb; $queue_table_name = $wpdb->prefix . 'aipkit_automated_task_queue'; $args = [ 'status' => 'approve', 'type' => 'comment', 'number' => 50, 'orderby' => 'comment_date_gmt', 'order' => 'ASC', ]; if (isset($task_config['no_reply_to_replies']) && $task_config['no_reply_to_replies'] === '1') { $args['parent'] = 0; } if ($last_run_time) { $args['date_query'] = [['column' => 'comment_date_gmt', 'after' => $last_run_time, 'inclusive' => false]]; } $post_types = $task_config['post_types_for_comments'] ?? ['post']; if (!empty($post_types)) { $args['post_type'] = $post_types; } $comments_to_process = get_comments($args); $queued_count = 0; if (empty($comments_to_process)) { return; } foreach ($comments_to_process as $comment) { $comment_id = $comment->comment_ID; $existing_item = $wpdb->get_var($wpdb->prepare("SELECT id FROM {$queue_table_name} WHERE task_id = %d AND target_identifier = %s", $task_id, $comment_id )); $existing_reply = get_comments([ 'parent' => $comment_id, 'meta_key' => '_aipkit_automated_reply', 'meta_value' => $task_id, 'count' => true ]); if ($existing_item || $existing_reply > 0) { continue; } $inserted = $wpdb->insert( $queue_table_name, [ 'task_id' => $task_id, 'target_identifier' => $comment_id, 'task_type' => 'community_reply_comments', 'item_config' => wp_json_encode($task_config), 'status' => 'pending', 'added_at' => current_time('mysql', 1) ], ['%d', '%d', '%s', '%s', '%s', '%s'] ); if ($inserted) { $queued_count++; } } } 